import React, { useState, useEffect } from 'react';
import { Plus, Search, Edit2, Trash2, Save, X, StickyNote } from 'lucide-react';

const API_URL = 'http://localhost:5000/api/notes';

const NotesApp = () => {
  const [notes, setNotes] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isCreating, setIsCreating] = useState(false);
  const [editingNote, setEditingNote] = useState(null);
  const [newNote, setNewNote] = useState({ title: '', content: '', color: '#FFE4B5' });
  const [loading, setLoading] = useState(true);

  const colors = ['#FFE4B5', '#B5E4FF', '#FFB5E4', '#B5FFE4', '#E4B5FF', '#FFD4B5'];

  // Lấy notes từ API
  useEffect(() => {
    fetchNotes();
  }, []);

  const fetchNotes = async () => {
    try {
      const response = await fetch(API_URL);
      const data = await response.json();
      setNotes(data);
      setLoading(false);
    } catch (error) {
      console.error('Lỗi khi tải notes:', error);
      setLoading(false);
    }
  };

  const createNote = async () => {
    if (!newNote.title.trim()) return;

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newNote)
      });
      const note = await response.json();
      setNotes([note, ...notes]);
      setNewNote({ title: '', content: '', color: '#FFE4B5' });
      setIsCreating(false);
    } catch (error) {
      console.error('Lỗi khi tạo note:', error);
    }
  };

  const updateNote = async () => {
    if (!editingNote.title.trim()) return;

    try {
      const response = await fetch(`${API_URL}/${editingNote._id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(editingNote)
      });
      const updatedNote = await response.json();
      setNotes(notes.map(n => n._id === updatedNote._id ? updatedNote : n));
      setEditingNote(null);
    } catch (error) {
      console.error('Lỗi khi cập nhật note:', error);
    }
  };

  const deleteNote = async (id) => {
    try {
      await fetch(`${API_URL}/${id}`, { method: 'DELETE' });
      setNotes(notes.filter(n => n._id !== id));
    } catch (error) {
      console.error('Lỗi khi xóa note:', error);
    }
  };

  const filteredNotes = notes.filter(note =>
    note.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    note.content.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const NoteCard = ({ note }) => (
    <div
      className="group relative rounded-2xl p-6 shadow-lg hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-1"
      style={{ backgroundColor: note.color }}
    >
      <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity duration-200 flex gap-2">
        <button
          onClick={() => setEditingNote(note)}
          className="p-2 bg-white rounded-full shadow-md hover:bg-blue-50 transition-colors"
        >
          <Edit2 size={16} className="text-blue-600" />
        </button>
        <button
          onClick={() => deleteNote(note._id)}
          className="p-2 bg-white rounded-full shadow-md hover:bg-red-50 transition-colors"
        >
          <Trash2 size={16} className="text-red-600" />
        </button>
      </div>
      <h3 className="text-xl font-bold mb-3 pr-20 text-gray-800">{note.title}</h3>
      <p className="text-gray-700 whitespace-pre-wrap mb-3">{note.content}</p>
      <p className="text-xs text-gray-600">
        {new Date(note.createdAt).toLocaleDateString('vi-VN', {
          day: '2-digit',
          month: '2-digit',
          year: 'numeric',
          hour: '2-digit',
          minute: '2-digit'
        })}
      </p>
    </div>
  );

  const NoteModal = ({ note, setNote, onSave, onClose, title }) => (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
      <div className="bg-white rounded-3xl shadow-2xl max-w-2xl w-full p-8 transform transition-all">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-gray-800">{title}</h2>
          <button
            onClick={onClose}
            className="p-2 hover:bg-gray-100 rounded-full transition-colors"
          >
            <X size={24} className="text-gray-600" />
          </button>
        </div>
        
        <input
          type="text"
          placeholder="Tiêu đề ghi chú..."
          value={note.title}
          onChange={(e) => setNote({ ...note, title: e.target.value })}
          className="w-full px-4 py-3 mb-4 text-xl font-semibold border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:outline-none transition-colors"
        />
        
        <textarea
          placeholder="Nội dung ghi chú..."
          value={note.content}
          onChange={(e) => setNote({ ...note, content: e.target.value })}
          className="w-full px-4 py-3 mb-4 h-48 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:outline-none resize-none transition-colors"
        />
        
        <div className="mb-6">
          <p className="text-sm font-semibold text-gray-700 mb-3">Chọn màu:</p>
          <div className="flex gap-3">
            {colors.map(color => (
              <button
                key={color}
                onClick={() => setNote({ ...note, color })}
                className={`w-12 h-12 rounded-full shadow-md hover:scale-110 transition-transform ${
                  note.color === color ? 'ring-4 ring-blue-500 ring-offset-2' : ''
                }`}
                style={{ backgroundColor: color }}
              />
            ))}
          </div>
        </div>
        
        <button
          onClick={onSave}
          className="w-full bg-gradient-to-r from-blue-500 to-purple-600 text-white py-4 rounded-xl font-semibold hover:from-blue-600 hover:to-purple-700 transition-all shadow-lg hover:shadow-xl flex items-center justify-center gap-2"
        >
          <Save size={20} />
          Lưu Ghi Chú
        </button>
      </div>
    </div>
  );

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 via-purple-50 to-pink-50 flex items-center justify-center">
        <div className="text-2xl text-gray-600">Đang tải...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-purple-50 to-pink-50">
      {/* Header */}
      <div className="bg-white shadow-md sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 py-6">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl shadow-lg">
                <StickyNote size={32} className="text-white" />
              </div>
              <h1 className="text-3xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
                Ghi Chú Của Tôi
              </h1>
            </div>
            <button
              onClick={() => setIsCreating(true)}
              className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-blue-500 to-purple-600 text-white rounded-xl font-semibold hover:from-blue-600 hover:to-purple-700 transition-all shadow-lg hover:shadow-xl transform hover:scale-105"
            >
              <Plus size={20} />
              Tạo Mới
            </button>
          </div>
          
          <div className="relative">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
            <input
              type="text"
              placeholder="Tìm kiếm ghi chú..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:outline-none transition-colors"
            />
          </div>
        </div>
      </div>

      {/* Notes Grid */}
      <div className="max-w-7xl mx-auto px-4 py-8">
        {filteredNotes.length === 0 ? (
          <div className="text-center py-20">
            <StickyNote size={64} className="mx-auto text-gray-300 mb-4" />
            <p className="text-xl text-gray-500">
              {searchTerm ? 'Không tìm thấy ghi chú nào' : 'Chưa có ghi chú. Hãy tạo ghi chú đầu tiên!'}
            </p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredNotes.map(note => (
              <NoteCard key={note._id} note={note} />
            ))}
          </div>
        )}
      </div>

      {/* Create Modal */}
      {isCreating && (
        <NoteModal
          note={newNote}
          setNote={setNewNote}
          onSave={createNote}
          onClose={() => {
            setIsCreating(false);
            setNewNote({ title: '', content: '', color: '#FFE4B5' });
          }}
          title="Tạo Ghi Chú Mới"
        />
      )}

      {/* Edit Modal */}
      {editingNote && (
        <NoteModal
          note={editingNote}
          setNote={setEditingNote}
          onSave={updateNote}
          onClose={() => setEditingNote(null)}
          title="Chỉnh Sửa Ghi Chú"
        />
      )}
    </div>
  );
};

export default NotesApp;
